svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
    var chartArea = svgEl.querySelector('#chart-area');
    var tip = svgEl.querySelector('#tip');
    var legendRoot = svgEl.querySelector('#legend-root');
    var plotL = 42, plotR = 840, plotT = 100, plotB = 500;
    var meta = {
      bw1: { label:'Cyan', value:'$72M', share:'38%' },
      bw2: { label:'Emerald', value:'$68M', share:'22%' },
      bw3: { label:'Amber', value:'$60M', share:'44%' },
      bw4: { label:'Rose', value:'$55M', share:'15%' },
      bw5: { label:'Violet', value:'$79M', share:'31%' },
      bw6: { label:'Blue', value:'$64M', share:'27%' },
      bw7: { label:'Teal', value:'$61M', share:'42%' },
      bw8: { label:'Other', value:'$48M', share:'12%' }
    };

    var fadeDurationSeconds = parseFloat(getComputedStyle(svgEl).getPropertyValue('--chart-fade-duration')) || 0.8;
    var bubGrps = ctx.$$all('.bub-g');
    var revealTiming = ctx.getStaggerTiming(bubGrps.length, { duration: fadeDurationSeconds }, svgEl);
    ctx.initRevealSequence(bubGrps, {
      animationName: 'dataFadeIn',
      duration: fadeDurationSeconds,
      easing: 'ease-out',
      delays: bubGrps.map(function (_, i) {
        return ctx.getStaggerDelay(i, bubGrps.length, null, svgEl);
      })
    });
    ctx.markReadyAfterReveal(chartArea, revealTiming.readyDelayMs);

    var dataItemEls = ctx.$$all('.data-item');
    ctx.initStandardTooltip(chartArea, dataItemEls, {
      leaveTarget: chartArea,
      tip: tip,
      plotL: plotL,
      plotR: plotR,
      plotT: plotT,
      plotB: plotB,
      boxHeight: 132,
      minWidth: 236,
      lineY: [0.30, 0.58, 0.80],
      trackPointer: false,
      getContent: function (itemEl) {
        var m = meta[itemEl.id] || {};
        return {
          primary: m.value || '',
          label: m.label || '',
          meta: (m.share || '') ? m.share + ' share' : ''
        };
      },
      getAnchor: function (itemEl) {
        var circle = itemEl.querySelector('circle');
        var x = parseFloat(circle.getAttribute('cx'));
        var y = parseFloat(circle.getAttribute('cy'));
        return { x: x, y: y };
      }
    });

    ctx.initStandardLegend({
      legendEl: legendRoot,
      title: 'SERIES',
      rowGap: 48,
      items: [
        { cls: 'series-1', label: 'Cyan', value: '$72M', swatchStyle: 'stroke:none' },
        { cls: 'series-2', label: 'Emerald', value: '$68M', swatchStyle: 'stroke:none' },
        { cls: 'series-3', label: 'Amber', value: '$60M', swatchStyle: 'stroke:none' },
        { cls: 'series-4', label: 'Rose', value: '$55M', swatchStyle: 'stroke:none' },
        { cls: 'series-5', label: 'Violet', value: '$79M', swatchStyle: 'stroke:none' }
      ]
    });
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
